$_MODULE['<{retractationcommande}prestashop>modal_c41af0bc59217001d2912ae37146555b'] = 'Herroeping bevestigen';
$_MODULE['<{retractationcommande}prestashop>modal_f64e4c1e50abe85bbda9fd9abadcaa91'] = 'Door te bevestigen wordt uw herroepingsverzoek doorgestuurd naar onze klantenservice en ontvangt u per e-mail een ontvangstbevestiging met een pdf-exemplaar (art. L221-21 van het Franse consumentenwetboek). Na controle van de voorwaarden (wettelijke termijn, uitsluitingen van art. L221-28) wordt de retourprocedure aan u meegedeeld — gelieve de producten niet terug te sturen voordat u deze hebt ontvangen. De terugbetaling vindt plaats uiterlijk 14 dagen na ontvangst van het goed of van het bewijs van verzending (verzendkosten inbegrepen bij volledige herroeping, naar rato in andere gevallen). De retourkosten blijven voor uw rekening.';
$_MODULE['<{retractationcommande}prestashop>modal_c3dfdd738e28bfabd19dd69e3b860058'] = 'Door te bevestigen wordt uw herroepingsverzoek doorgestuurd naar onze klantenservice en ontvangt u per e-mail een ontvangstbevestiging met een pdf-exemplaar (art. L221-21 van het Franse consumentenwetboek). Aangezien uw bestelling al is verzonden, kunt u het pakket bij levering weigeren; als u het ontvangt, open het dan niet en volg de retourprocedure die onze klantenservice u zal toesturen. De terugbetaling vindt plaats uiterlijk 14 dagen na ontvangst van het goed of van het bewijs van de terugzending ervan. De retourkosten blijven voor uw rekening.';
$_MODULE['<{retractationcommande}prestashop>modal_a50e61a0c90d69685028d751c58e4b92'] = 'Door te bevestigen wordt uw herroepingsverzoek doorgestuurd naar onze klantenservice en ontvangt u per e-mail een ontvangstbevestiging met een pdf-exemplaar (art. L221-21 van het Franse consumentenwetboek). Aangezien uw bestelling nog niet is verzonden, is geen productretour nodig: na controle (uitsluitingen van art. L221-28) wordt de verzending geannuleerd en wordt het volledige betaalde bedrag uiterlijk 14 dagen na uw verzoek terugbetaald via hetzelfde betaalmiddel.';
$_MODULE['<{retractationcommande}prestashop>formulaire_c690c88abeab5fe0fa53c961a8c22564'] = 'Mijn herroepingsrecht uitoefenen';
