$_MODULE['<{retractationcommande}prestashop>formulaire_1e8ba54ca05a4d16b3314cd53c6d7847'] = 'Herroepingsrecht uitoefenbaar';
$_MODULE['<{retractationcommande}prestashop>formulaire_e1b2374a2b9670a77ca0c7ae9199ad3a'] = 'Deze bestelling komt niet (meer) in aanmerking voor online herroeping: wettelijke termijn verstreken, verzoek reeds ingediend of bestelling niet van toepassing. Neem voor vragen contact op met onze klantenservice.';
$_MODULE['<{retractationcommande}prestashop>formulaire_8fdb7ef7cb418c21ac083c86b78ce700'] = 'Het herroepingsrecht is niet van toepassing op bepaalde overeenkomsten (art. L221-28 consumentenwetboek: op maat gemaakte of gepersonaliseerde goederen, bederfelijke goederen, om hygiënische redenen ontzegelde goederen, enz.). Na indiening wordt uw verzoek gecontroleerd door onze klantenservice, die u de retourprocedure toestuurt. De terugbetaling vindt plaats uiterlijk 14 dagen na ontvangst van het goed of van het bewijs van verzending, via hetzelfde betaalmiddel. De retourkosten blijven voor uw rekening.';
$_MODULE['<{retractationcommande}prestashop>formulaire_40333b8af27e3198afa43c960e43a3b8'] = 'Herroepingsrecht';
