$_MODULE['<{retractationcommande}prestashop>pdf-accuse_0acbcac4025fa540444c48cd5594df23'] = 'Verzendkosten (terugbetaald — volledige herroeping)';
$_MODULE['<{retractationcommande}prestashop>pdf-accuse_b01439257d2c4065fdfa7b0ece09c658'] = 'Terug te betalen bedrag (schatting)';
$_MODULE['<{retractationcommande}prestashop>pdf-accuse_d7946d02e12c5949ea9345ba89b095c4'] = 'Gedeeltelijke herroeping: de verzendkosten worden naar rato van de teruggestuurde goederen terugbetaald (art. L221-24 van het Franse consumentenwetboek). Het definitieve bedrag wordt u door onze klantenservice bevestigd.';
$_MODULE['<{retractationcommande}prestashop>pdf-accuse_a326ee07399805b54dda859c82d08e17'] = 'Bericht van de consument';
$_MODULE['<{retractationcommande}prestashop>pdf-accuse_b6aaa57d1a0559fa210245cf8167735e'] = 'Vervolg van de procedure';
$_MODULE['<{retractationcommande}prestashop>pdf-accuse_fb258aad76f4abfa89becfda83844199'] = 'Uw verzoek wordt gecontroleerd door onze klantenservice (naleving van de wettelijke termijn, uitsluitingen voorzien in artikel L221-28 van het Franse consumentenwetboek). Indien conform, wordt de retourprocedure u per e-mail toegestuurd. Gelieve het/de product(en) niet terug te sturen voordat u deze hebt ontvangen. De terugbetaling vindt plaats uiterlijk 14 dagen na ontvangst van het goed of van het bewijs van verzending, via hetzelfde betaalmiddel als gebruikt bij de bestelling (art. L221-24). De directe retourkosten blijven voor uw rekening (art. L221-23).';
$_MODULE['<{retractationcommande}prestashop>pdf-accuse_f4a5fa56c47e4ce919d925339edd26af'] = 'Aangezien uw bestelling op het moment van uw verzoek al was verzonden, kunt u het pakket bij levering weigeren of, als u het ontvangt, de retourprocedure volgen die onze klantenservice u na controle zal toesturen (uitsluitingen voorzien in artikel L221-28 van het Franse consumentenwetboek). De terugbetaling vindt plaats uiterlijk 14 dagen na ontvangst van het goed of van het bewijs van de terugzending ervan, via hetzelfde betaalmiddel als gebruikt bij de bestelling (art. L221-24). De directe retourkosten blijven voor uw rekening (art. L221-23).';
$_MODULE['<{retractationcommande}prestashop>pdf-accuse_cfdcc6b063cf374f1884714702a0756f'] = 'Aangezien uw bestelling op het moment van uw verzoek nog niet was verzonden, is geen productretour nodig. Na controle door onze klantenservice (uitsluitingen voorzien in artikel L221-28 van het Franse consumentenwetboek) wordt de verzending geannuleerd en wordt het volledige betaalde bedrag uiterlijk 14 dagen na uw verzoek terugbetaald via hetzelfde betaalmiddel als gebruikt bij de bestelling (art. L221-24).';
$_MODULE['<{retractationcommande}prestashop>pdf-accuse_5c2d9de00ffacf2c364b00b78de3b779'] = 'Dit document geldt als ontvangstbevestiging van uw herroeping. Bewaar het — uw referentie te vermelden bij elke communicatie:';
$_MODULE['<{retractationcommande}prestashop>pdf-droits_cd869423e6e1712e244df7d46926ae55'] = 'Herinnering aan uw rechten — herroepingsrecht';
$_MODULE['<{retractationcommande}prestashop>pdf-droits_28f6dc3c50525ce42dc3c3c6230b2e04'] = 'De termijn';
$_MODULE['<{retractationcommande}prestashop>pdf-droits_24e62b7e04a04435c6493925063099d7'] = 'U beschikt over een termijn van 14 dagen om te herroepen, zonder uw beslissing te hoeven motiveren (art. L221-18 van het Franse consumentenwetboek). De telling begint de dag na de levering van het goed (of na het sluiten van de overeenkomst bij een dienst). Als de termijn afloopt op een zaterdag, zondag of feestdag, wordt hij verlengd tot de eerstvolgende werkdag.';
$_MODULE['<{retractationcommande}prestashop>pdf-droits_ca4bdfe353ca54b512aa784846d90e0f'] = 'De terugbetaling';
$_MODULE['<{retractationcommande}prestashop>pdf-droits_6541cabbb055c914336220caeaf4b99e'] = 'De terugbetaling betreft het volledige betaalde bedrag, inclusief de standaard verzendkosten (naar rato bij gedeeltelijke herroeping). Zij vindt plaats uiterlijk 14 dagen na ontvangst van het goed of van het bewijs van de verzending ervan, via hetzelfde betaalmiddel als gebruikt bij de bestelling (art. L221-24). De directe retourkosten van het goed blijven voor uw rekening (art. L221-23).';
$_MODULE['<{retractationcommande}prestashop>pdf-droits_364ec46bb0eefd5863d785498e0c8539'] = 'De uitzonderingen (art. L221-28)';
$_MODULE['<{retractationcommande}prestashop>pdf-droits_cb0665e6df823aae3b2992c440175070'] = 'Het herroepingsrecht kan met name niet worden uitgeoefend voor:';
$_MODULE['<{retractationcommande}prestashop>pdf-droits_7e1ea9778afc631312c1791d817f91c0'] = 'goederen die zijn vervaardigd volgens uw specificaties of duidelijk gepersonaliseerd;';
$_MODULE['<{retractationcommande}prestashop>pdf-droits_0b6b365148cc6a798a4d9bec4e636d96'] = 'goederen die snel kunnen bederven of verouderen;';
$_MODULE['<{retractationcommande}prestashop>pdf-droits_9efb6136f62e038628c899b282f64011'] = 'goederen die na levering zijn ontzegeld en om redenen van hygiëne of gezondheidsbescherming niet kunnen worden teruggestuurd;';
$_MODULE['<{retractationcommande}prestashop>pdf-droits_8b8f626ccf32831a3fee474f675ea152'] = 'audio-/video-opnames of software die na levering zijn ontzegeld;';
$_MODULE['<{retractationcommande}prestashop>pdf-droits_01449e6b663bbee9d407376945b3c9b6'] = 'digitale inhoud die zonder materiële drager wordt geleverd en waarvan de uitvoering met uw toestemming is begonnen;';
$_MODULE['<{retractationcommande}prestashop>pdf-droits_1d3b84dba66d1eb114fd8af178aa04d6'] = 'goederen die na levering onlosmakelijk met andere artikelen zijn vermengd.';
$_MODULE['<{retractationcommande}prestashop>pdf-droits_0095888b608335ea5982af9ada860f76'] = 'Het vervolg van uw verzoek';
$_MODULE['<{retractationcommande}prestashop>pdf-droits_109c56e11ccf08ecc9e243bd1c4cb25f'] = 'Onze klantenservice controleert uw verzoek en stuurt u vervolgens de retourprocedure per e-mail toe. Gelieve het/de product(en) niet terug te sturen voordat u deze hebt ontvangen, en de goederen volledig en in hun oorspronkelijke staat te retourneren.';
$_MODULE['<{retractationcommande}prestashop>pdf-droits_14859a97695af0f293d5dd18358f472e'] = 'Bestelling al verzonden: u kunt het pakket bij levering weigeren. Als u het ontvangt, open het dan niet en volg de retourprocedure die onze klantenservice u zal toesturen. Retourneer de goederen volledig en in hun oorspronkelijke staat.';
$_MODULE['<{retractationcommande}prestashop>pdf-droits_de7d1a2208e88e0679183aa747db6042'] = 'Niet-verzonden bestelling: geen productretour nodig. Onze klantenservice controleert uw verzoek, annuleert de verzending en gaat over tot terugbetaling.';
$_MODULE['<{retractationcommande}prestashop>pdf-droits_2f45a1c26bcfdf568c08ed1a390d3cbd'] = 'In geval van geschil';
$_MODULE['<{retractationcommande}prestashop>pdf-droits_804c0cd637a7c9607f4e30b77e11a8ba'] = 'Als u van mening bent dat uw verzoek niet conform de regelgeving is behandeld, kunt u contact opnemen met onze klantenservice en vervolgens kosteloos een beroep doen op een consumentenbemiddelaar (art. L612-1 van het Franse consumentenwetboek).';
