$_MODULE['<{retractationcommande}prestashop>demande_b0998d501f75050aa4045d17399c25d0'] = 'Kan het verzoek niet opslaan. Neem contact op met de klantenservice.';
$_MODULE['<{retractationcommande}prestashop>demande_9914a2c75cdd71876e656e7621e47300'] = 'Uw herroeping is geregistreerd onder referentie %s. Er is u een ontvangstbevestiging per e-mail gestuurd. Onze klantenservice zal uw verzoek controleren en u de retourprocedure toesturen.';
$_MODULE['<{retractationcommande}prestashop>demande_049d1d68c945230da39359dbd32e1d48'] = 'Uw herroeping is geregistreerd onder referentie %s. Er is u een ontvangstbevestiging per e-mail gestuurd. Aangezien uw bestelling al is verzonden, kunt u het pakket bij levering weigeren of, als u het ontvangt, de retourprocedure volgen die onze klantenservice u zal toesturen.';
$_MODULE['<{retractationcommande}prestashop>demande_f49c93cbb2dab9d8c4b41d7e8a0f346d'] = 'Uw herroeping is geregistreerd onder referentie %s. Er is u een ontvangstbevestiging per e-mail gestuurd. Aangezien uw bestelling nog niet is verzonden, is geen productretour nodig: na controle wordt de verzending geannuleerd en wordt u terugbetaald.';
$_MODULE['<{retractationcommande}prestashop>demande_5a06e6b127a7d1baaf18d35bde389969'] = 'Onze klantenservice zal de voorwaarden van uw verzoek controleren (wettelijke termijn van 14 dagen, uitsluitingen van artikel L221-28). Indien conform, wordt de retourprocedure u per e-mail toegestuurd, waarna de terugbetaling plaatsvindt uiterlijk 14 dagen na ontvangst van het goed of van het bewijs van verzending. Gelieve het product niet terug te sturen voordat u de retourprocedure hebt ontvangen.';
$_MODULE['<{retractationcommande}prestashop>demande_b91f8258aeb37ba358b04427913bd6b1'] = 'Te controleren: termijn van 14 dagen, wettelijke uitsluitingen (art. L221-28), reeds geretourneerde producten.';
$_MODULE['<{retractationcommande}prestashop>demande_869cbd236cf583ec668d9f90469f561c'] = 'Uw bestelling is al verzonden en is onderweg. U kunt het pakket bij levering weigeren; als u het ontvangt, open het dan niet en wacht op de retourprocedure die onze klantenservice u na controle zal toesturen. De terugbetaling vindt plaats uiterlijk 14 dagen na ontvangst van het goed of van het bewijs van de terugzending ervan.';
$_MODULE['<{retractationcommande}prestashop>demande_e32237222087921238a826c436916179'] = 'BESTELLING VERZONDEN (onderweg) — het pakket is vertrokken: voorzie een pakketweigering of een retour. Te controleren: wettelijke uitsluitingen (art. L221-28). De termijn van 14 dagen begint pas bij de levering.';
$_MODULE['<{retractationcommande}prestashop>demande_ba6e3c755dec44b85c76f4e9e919450b'] = 'Aangezien uw bestelling nog niet is verzonden, is geen productretour nodig. Na controle van uw verzoek door onze klantenservice wordt de verzending geannuleerd en wordt het volledige betaalde bedrag uiterlijk 14 dagen na uw verzoek terugbetaald via hetzelfde betaalmiddel (art. L221-24).';
$_MODULE['<{retractationcommande}prestashop>demande_ecbc815f858a7d4a0ff0fe67f6eea2a3'] = 'NIET-VERZONDEN BESTELLING — annulering vóór verzending: geen productretour verwacht. Te controleren: wettelijke uitsluitingen (art. L221-28). Vergeet niet de verzending te blokkeren vóór de validatie.';
$_MODULE['<{retractationcommande}prestashop>demande_00e9581137cc9fcce29afdb92e74d13a'] = 'Verzonden, onderweg';
$_MODULE['<{retractationcommande}prestashop>demande_5f0d073c461f238ea2622dc70766a38f'] = 'Niet verzonden op het moment van het verzoek';
$_MODULE['<{retractationcommande}prestashop>demande_a860874ff76e61887b36e2c13ab146f1'] = 'Ontvangstbevestiging van uw herroepingsverzoek';
$_MODULE['<{retractationcommande}prestashop>demande_cb082ed668c8c616513cef755d589f79'] = 'Nieuw te controleren herroepingsverzoek';
